mapper.select:
select * from ygt_order_candidate_item
and ygt_oci_candidate_id = #{candidateId}
order by ygt_order_candidate_item_id asc
limit #{offset}, #{limit}

mapper.update:
update ygt_order_candidate_item
ygt_oci_campaign_goods_id = #{ygtOciCampaignGoodsId}, ygt_oci_nx_community_goods_id = #{ygtOciNxCommunityGoodsId}, ygt_oci_goods_name_snapshot = #{ygtOciGoodsNameSnapshot}, ygt_oci_quantity = #{ygtOciQuantity}, ygt_oci_unit = #{ygtOciUnit}, ygt_oci_price_snapshot = #{ygtOciPriceSnapshot}, ygt_oci_amount = #{ygtOciAmount}, ygt_oci_remark = #{ygtOciRemark}, ygt_oci_confidence = #{ygtOciConfidence}, ygt_oci_manual_adjusted = #{ygtOciManualAdjusted}, ygt_oci_update_time = now()
where ygt_order_candidate_item_id = #{ygtOrderCandidateItemId}
